//        加 fallback：itemMatching 不可用時退回 pairedItem.item

const items = $input.all();
const allReadItems = $('Read 知識文件').all();

function filterPrintable(text) {
  if (!text || typeof text !== 'string') return '';
  const printableMatches = text.match(/[\u4e00-\u9fff\u3000-\u303f\uff00-\uffefa-zA-Z0-9\s.,!?;:()\[\]{}\-+="'\/_*&%$#@~|<>\n]/g);
  const ratio = printableMatches ? printableMatches.length / text.length : 0;
  return ratio > 0.7 ? text : '';
}

const stats = { totalFiles: allReadItems.length, indexed: 0, skipped: 0, skippedNoFileName: 0, totalChunks: 0 };

// 建 textMap：fileName → 抽出的純文字
const textMap = new Map();
for (let i = 0; i < items.length; i++) {
  const it = items[i];
  let fn = null;
  try {
    // n8n 官方 API：追溯到 Read 知識文件對應 item（跨 Switch 分流穩定）
    const readItem = $('Read 知識文件').itemMatching(i);
    fn = readItem?.json?.fileName;
  } catch (e) {
    // fallback：直接用 pairedItem.item 對 allReadItems index
    const pi = typeof it.pairedItem === 'number' ? it.pairedItem : it.pairedItem?.item;
    if (pi != null) fn = allReadItems[pi]?.json?.fileName;
  }
  if (!fn) { stats.skippedNoFileName++; continue; }
  const t = it.json?.text ?? it.json?.data;
  if (t != null) textMap.set(fn, String(t));
}

const chunks = [];

for (let i = 0; i < allReadItems.length; i++) {
  const readItem = allReadItems[i];
  if (!readItem?.binary?.data) { stats.skipped++; continue; }

  const fileName = readItem.json.fileName || ('unknown-' + (i + 1));
  const rawText = textMap.get(fileName) ?? '';
  const cleanText = filterPrintable(rawText);

  if (!cleanText || cleanText.length < 50) {
    stats.skipped++;
    continue;
  }

  stats.indexed++;
  const size = 500, overlap = 50;
  for (let p = 0; p < cleanText.length; p += (size - overlap)) {
    const chunk = cleanText.substring(p, p + size).trim();
    if (chunk.length < 50) continue;
    chunks.push({ source: fileName, pos: p, text: chunk, indexedAt: new Date().toISOString() });
  }
}

stats.totalChunks = chunks.length;
const jsonl = chunks.map(c => JSON.stringify(c)).join('\n');

return [{
  json: { chunkCount: chunks.length, indexPath: '/files/shared/knowledge-index/knowledge-index.jsonl', _stats: stats },
  binary: { data: { data: Buffer.from(jsonl).toString('base64'), mimeType: 'application/jsonl', fileName: 'knowledge-index.jsonl' } }
}];

