const question = $('Webhook: kb-ask').first().json.body?.question
  || $('Webhook: kb-ask').first().json.query?.question
  || '請告訴我你能回答什麼？';

const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const jsonlText = buf.toString('utf-8');
const chunks = jsonlText.split('\n').filter(l => l).map(l => JSON.parse(l));

function tokenize(s) {
  const tokens = new Set();
  for (const m of s.matchAll(/[a-zA-Z0-9]{2,}/g)) tokens.add(m[0].toLowerCase());
  const cjkSegments = s.split(/[^\u4e00-\u9fff\u3400-\u4dbf]+/).filter(seg => seg.length >= 2);
  for (const seg of cjkSegments) {
    for (let i = 0; i < seg.length - 1; i++) {
      tokens.add(seg.substring(i, i + 2));
    }
    if (seg.length >= 3) tokens.add(seg);
  }
  return [...tokens];
}

const qTokens = tokenize(question);
if (qTokens.length === 0) {
  return [{ json: { answer: '問題太短，請改用 ≥2 個字。', sources: [], question } }];
}

// 動態 minScore：1 token query 用 >=1（如純英文「kubernetes」），多 token 用 >=2 過濾噪音
const minScore = qTokens.length === 1 ? 1 : 2;

const scored = chunks.map(c => {
  const lower = c.text.toLowerCase();
  const score = qTokens.reduce((s, t) => s + (lower.includes(t) ? 1 : 0), 0);
  return { ...c, score };
}).filter(c => c.score >= minScore)
  .sort((a, b) => b.score - a.score)
  .slice(0, 5);

if (scored.length === 0) {
  return [{ json: { answer: '資料庫內無此資訊。請改問其他問題或確認 knowledge-docs/ 內檔案已索引。', sources: [], question } }];
}

const context = scored.map((c, i) => '[' + (i+1) + '] (' + c.source + ')\n' + c.text).join('\n\n');
const prompt = '你是企業知識庫問答助手。根據下面 context 回答用戶問題（繁體中文）。如果 context 不足以回答，誠實說「資料庫內無此資訊」。每段答覆引用來源編號 [1] [2] 等。\n\n<question>' + question + '</question>\n\n<context>\n' + context + '\n</context>';

const lpResult = await lpCall.call(this, {
  prompt,
  gen: { temperature: 0.4, maxOutputTokens: 800 }
});
const answer = lpResult.ok
  ? (lpResult.text || 'AI 無回應')
  : '查詢失敗：' + lpResult.error;

return [{
  json: {
    question, answer,
    sources: scored.map((c, i) => ({ ref: i+1, file: c.source, snippet: c.text.substring(0, 100) }))
  }
}];

